# solution.py
"""MultiAgentTaskScheduler.

A self-contained, thread-safe, standard-library-only coordination engine that
lets multiple *agents* execute *tasks* cooperatively.  It supports:

* Task definition (name, description, priority, required resources, optional
  estimated duration and deadline).
* Agent registration with skills/resources, capacity and availability.
* Manual and automatic assignment, plus dynamic reassignment driven by agent
  availability and task urgency.
* Real-time progress feedback: completion status, progress percentage,
  estimated time to completion and recorded issues.
* Inter-agent communication: a lightweight chat / shared-status feed with
  per-agent and broadcast notifications.
* Adaptation to change: when tasks are added, finished early or an agent
  becomes unavailable the queue is reorganised and affected agents notified.
* A management surface: filtering, sorting and searching of tasks plus agent
  performance monitoring and dashboards.
* A complete history log of every task (start/end times, the agents involved
  and any notes or feedback) with CSV export.

The whole system lives in a single module so it can be dropped in as
``solution.py``.  Everything is ASCII-only and depends solely on the Python
standard library (tested on CPython 3.12).
"""

from __future__ import annotations

import csv
import copy
import functools
import io
import threading
from datetime import datetime, timedelta, timezone
from enum import Enum

__all__ = [
    "SchedulerError",
    "ValidationError",
    "NotFoundError",
    "ConflictError",
    "Priority",
    "TaskStatus",
    "AgentStatus",
    "Agent",
    "Task",
    "Message",
    "Notification",
    "HistoryEntry",
    "MultiAgentTaskScheduler",
]


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------
class SchedulerError(Exception):
    """Base class for every error raised by the scheduler."""


class ValidationError(SchedulerError):
    """Raised when caller supplied data is malformed or out of range."""


class NotFoundError(SchedulerError):
    """Raised when a referenced agent, task or message does not exist."""


class ConflictError(SchedulerError):
    """Raised for illegal state transitions or capacity/availability clashes."""


# ---------------------------------------------------------------------------
# Sentinel for "argument not supplied" in update_* methods
# ---------------------------------------------------------------------------
class _Unset:
    """Singleton marker distinguishing "omitted" from an explicit ``None``."""

    _instance = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
        return cls._instance

    def __repr__(self):  # pragma: no cover - debugging aid
        return "UNSET"

    def __bool__(self):
        return False


UNSET = _Unset()


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class Priority(Enum):
    """Task priority; higher value == more important / urgent."""

    LOW = 1
    MEDIUM = 2
    HIGH = 3
    URGENT = 4

    @classmethod
    def coerce(cls, value):
        """Accept a :class:`Priority`, its name (case-insensitive) or rank int."""
        if isinstance(value, cls):
            return value
        if isinstance(value, bool):
            raise ValidationError("priority must not be a bool")
        if isinstance(value, int):
            for member in cls:
                if member.value == value:
                    return member
            raise ValidationError("priority rank out of range: %r" % (value,))
        if isinstance(value, str):
            key = value.strip().upper()
            if key in cls.__members__:
                return cls[key]
            if key.isdigit():
                return cls.coerce(int(key))
            raise ValidationError("unknown priority: %r" % (value,))
        raise ValidationError("invalid priority: %r" % (value,))


class TaskStatus(Enum):
    """Lifecycle states of a task."""

    PENDING = "pending"          # created / queued, no agent
    ASSIGNED = "assigned"        # owned by an agent, not started
    IN_PROGRESS = "in_progress"  # actively being worked on
    BLOCKED = "blocked"          # halted by an issue
    COMPLETED = "completed"      # finished successfully
    CANCELLED = "cancelled"      # abandoned

    @property
    def is_terminal(self):
        return self in (TaskStatus.COMPLETED, TaskStatus.CANCELLED)

    @property
    def is_active(self):
        """True when the task occupies an agent's capacity."""
        return self in (
            TaskStatus.ASSIGNED,
            TaskStatus.IN_PROGRESS,
            TaskStatus.BLOCKED,
        )

    @classmethod
    def coerce(cls, value):
        if isinstance(value, cls):
            return value
        if isinstance(value, str):
            key = value.strip().lower()
            for member in cls:
                if member.value == key or member.name.lower() == key:
                    return member
        raise ValidationError("unknown task status: %r" % (value,))


class AgentStatus(Enum):
    """Derived availability state of an agent."""

    AVAILABLE = "available"  # online with spare capacity
    BUSY = "busy"            # online but fully loaded
    OFFLINE = "offline"      # unavailable


# ---------------------------------------------------------------------------
# Time helpers
# ---------------------------------------------------------------------------
def _utcnow():
    return datetime.now(timezone.utc)


def _as_aware(dt):
    """Normalise a datetime to timezone-aware UTC."""
    if dt.tzinfo is None:
        return dt.replace(tzinfo=timezone.utc)
    return dt


def _epoch(dt):
    """Sortable float seconds for a datetime (``None`` -> +infinity)."""
    if dt is None:
        return float("inf")
    return _as_aware(dt).timestamp()


def _iso(dt):
    return None if dt is None else _as_aware(dt).isoformat()


# ---------------------------------------------------------------------------
# Validation helpers
# ---------------------------------------------------------------------------
def _require_text(value, field):
    if not isinstance(value, str):
        raise ValidationError("%s must be a string" % field)
    text = value.strip()
    if not text:
        raise ValidationError("%s must not be empty" % field)
    return text


def _optional_text(value, field):
    if value is None:
        return ""
    if not isinstance(value, str):
        raise ValidationError("%s must be a string" % field)
    return value.strip()


def _normalize_resources(values, field="resources"):
    """Return a set of lower-cased resource tokens from an iterable."""
    if values is None:
        return set()
    if isinstance(values, (str, bytes)):
        raise ValidationError("%s must be an iterable of strings, not a string" % field)
    out = set()
    try:
        iterator = iter(values)
    except TypeError as exc:  # not iterable
        raise ValidationError("%s must be iterable" % field) from exc
    for item in iterator:
        if not isinstance(item, str):
            raise ValidationError("%s entries must be strings" % field)
        token = item.strip().lower()
        if token:
            out.add(token)
    return out


def _validate_number(value, field, *, allow_none=True, minimum=None):
    if value is None:
        if allow_none:
            return None
        raise ValidationError("%s is required" % field)
    if isinstance(value, bool) or not isinstance(value, (int, float)):
        raise ValidationError("%s must be a number" % field)
    if minimum is not None and value < minimum:
        raise ValidationError("%s must be >= %s" % (field, minimum))
    return float(value)


def _validate_deadline(value):
    if value is None:
        return None
    if not isinstance(value, datetime):
        raise ValidationError("deadline must be a datetime")
    return _as_aware(value)


# ---------------------------------------------------------------------------
# Entities
# ---------------------------------------------------------------------------
class Agent:
    """A worker that can be assigned tasks."""

    __slots__ = (
        "id",
        "name",
        "skills",
        "capacity",
        "online",
        "created_at",
        "active_task_ids",
        "completed_tasks",
        "cancelled_tasks",
        "total_completion_seconds",
        "issues_reported",
        "assignments_count",
    )

    def __init__(self, agent_id, name, skills, capacity, created_at):
        self.id = agent_id
        self.name = name
        self.skills = set(skills)
        self.capacity = capacity
        self.online = True
        self.created_at = created_at
        self.active_task_ids = set()
        self.completed_tasks = 0
        self.cancelled_tasks = 0
        self.total_completion_seconds = 0.0
        self.issues_reported = 0
        self.assignments_count = 0

    @property
    def load(self):
        return len(self.active_task_ids)

    @property
    def has_capacity(self):
        return self.online and self.load < self.capacity

    @property
    def status(self):
        if not self.online:
            return AgentStatus.OFFLINE
        if self.load >= self.capacity:
            return AgentStatus.BUSY
        return AgentStatus.AVAILABLE

    @property
    def average_completion_seconds(self):
        if self.completed_tasks == 0:
            return None
        return self.total_completion_seconds / self.completed_tasks

    def can_handle(self, required_resources):
        return set(required_resources).issubset(self.skills)

    def clone(self):
        return copy.deepcopy(self)

    def to_dict(self):
        return {
            "id": self.id,
            "name": self.name,
            "skills": sorted(self.skills),
            "capacity": self.capacity,
            "online": self.online,
            "status": self.status.value,
            "load": self.load,
            "active_task_ids": sorted(self.active_task_ids),
            "completed_tasks": self.completed_tasks,
            "cancelled_tasks": self.cancelled_tasks,
            "assignments_count": self.assignments_count,
            "issues_reported": self.issues_reported,
            "average_completion_seconds": self.average_completion_seconds,
            "created_at": _iso(self.created_at),
        }

    def __repr__(self):  # pragma: no cover - debugging aid
        return "Agent(id=%r, name=%r, status=%s, load=%d/%d)" % (
            self.id,
            self.name,
            self.status.value,
            self.load,
            self.capacity,
        )


class Task:
    """A unit of work."""

    __slots__ = (
        "id",
        "name",
        "description",
        "priority",
        "required_resources",
        "estimated_duration",
        "deadline",
        "status",
        "assigned_agent_id",
        "progress",
        "issues",
        "feedback",
        "assigned_history",
        "created_at",
        "started_at",
        "completed_at",
        "updated_at",
    )

    def __init__(
        self,
        task_id,
        name,
        description,
        priority,
        required_resources,
        estimated_duration,
        deadline,
        created_at,
    ):
        self.id = task_id
        self.name = name
        self.description = description
        self.priority = priority
        self.required_resources = set(required_resources)
        self.estimated_duration = estimated_duration  # seconds or None
        self.deadline = deadline                       # datetime or None
        self.status = TaskStatus.PENDING
        self.assigned_agent_id = None
        self.progress = 0.0                            # 0..100
        self.issues = []                               # list of dicts
        self.feedback = []                             # list of dicts
        self.assigned_history = []                     # agent ids ever assigned
        self.created_at = created_at
        self.started_at = None
        self.completed_at = None
        self.updated_at = created_at

    @property
    def is_open(self):
        return not self.status.is_terminal

    def is_overdue(self, now):
        return (
            self.deadline is not None
            and not self.status.is_terminal
            and _as_aware(self.deadline) < now
        )

    def duration_seconds(self):
        if self.started_at is None or self.completed_at is None:
            return None
        return (self.completed_at - self.started_at).total_seconds()

    def clone(self):
        return copy.deepcopy(self)

    def to_dict(self):
        return {
            "id": self.id,
            "name": self.name,
            "description": self.description,
            "priority": self.priority.name,
            "priority_rank": self.priority.value,
            "required_resources": sorted(self.required_resources),
            "estimated_duration": self.estimated_duration,
            "deadline": _iso(self.deadline),
            "status": self.status.value,
            "assigned_agent_id": self.assigned_agent_id,
            "progress": self.progress,
            "issues": [dict(i) for i in self.issues],
            "feedback": [dict(f) for f in self.feedback],
            "assigned_history": list(self.assigned_history),
            "created_at": _iso(self.created_at),
            "started_at": _iso(self.started_at),
            "completed_at": _iso(self.completed_at),
            "updated_at": _iso(self.updated_at),
        }

    def __repr__(self):  # pragma: no cover - debugging aid
        return "Task(id=%r, name=%r, priority=%s, status=%s)" % (
            self.id,
            self.name,
            self.priority.name,
            self.status.value,
        )


class Message:
    """A chat / shared-status message between agents."""

    __slots__ = ("id", "sender_id", "recipient_id", "task_id", "content", "timestamp")

    def __init__(self, message_id, sender_id, recipient_id, task_id, content, timestamp):
        self.id = message_id
        self.sender_id = sender_id
        self.recipient_id = recipient_id  # None == broadcast
        self.task_id = task_id            # optional context
        self.content = content
        self.timestamp = timestamp

    @property
    def is_broadcast(self):
        return self.recipient_id is None

    def clone(self):
        return copy.deepcopy(self)

    def to_dict(self):
        return {
            "id": self.id,
            "sender_id": self.sender_id,
            "recipient_id": self.recipient_id,
            "task_id": self.task_id,
            "content": self.content,
            "timestamp": _iso(self.timestamp),
        }

    def __repr__(self):  # pragma: no cover - debugging aid
        target = "all" if self.is_broadcast else self.recipient_id
        return "Message(id=%r, from=%r, to=%s)" % (self.id, self.sender_id, target)


class Notification:
    """An event delivered to an agent (or broadcast to all)."""

    __slots__ = (
        "id",
        "recipient_id",
        "type",
        "message",
        "task_id",
        "timestamp",
        "read",
    )

    def __init__(self, notif_id, recipient_id, ntype, message, task_id, timestamp):
        self.id = notif_id
        self.recipient_id = recipient_id  # None == broadcast
        self.type = ntype
        self.message = message
        self.task_id = task_id
        self.timestamp = timestamp
        self.read = False

    def clone(self):
        return copy.deepcopy(self)

    def to_dict(self):
        return {
            "id": self.id,
            "recipient_id": self.recipient_id,
            "type": self.type,
            "message": self.message,
            "task_id": self.task_id,
            "timestamp": _iso(self.timestamp),
            "read": self.read,
        }

    def __repr__(self):  # pragma: no cover - debugging aid
        return "Notification(id=%r, to=%r, type=%r)" % (
            self.id,
            self.recipient_id,
            self.type,
        )


class HistoryEntry:
    """An immutable audit-log record."""

    __slots__ = ("id", "task_id", "event", "agent_id", "note", "timestamp")

    def __init__(self, entry_id, task_id, event, agent_id, note, timestamp):
        self.id = entry_id
        self.task_id = task_id
        self.event = event
        self.agent_id = agent_id
        self.note = note
        self.timestamp = timestamp

    def clone(self):
        return copy.deepcopy(self)

    def to_dict(self):
        return {
            "id": self.id,
            "task_id": self.task_id,
            "event": self.event,
            "agent_id": self.agent_id,
            "note": self.note,
            "timestamp": _iso(self.timestamp),
        }

    def __repr__(self):  # pragma: no cover - debugging aid
        return "HistoryEntry(id=%r, task=%r, event=%r)" % (
            self.id,
            self.task_id,
            self.event,
        )


# ---------------------------------------------------------------------------
# Locking decorator
# ---------------------------------------------------------------------------
def _synchronized(method):
    @functools.wraps(method)
    def wrapper(self, *args, **kwargs):
        with self._lock:
            return method(self, *args, **kwargs)

    return wrapper


# ---------------------------------------------------------------------------
# The scheduler
# ---------------------------------------------------------------------------
class MultiAgentTaskScheduler:
    """Coordinate the execution of tasks across multiple agents.

    The instance is fully thread-safe: every public method acquires a single
    re-entrant lock, so the object may be shared freely between threads.  All
    getters return deep copies, so callers can never mutate internal state by
    holding on to a returned object.
    """

    def __init__(self, now=None, auto_assign_on_create=False, auto_reassign=True):
        self._lock = threading.RLock()
        self._now = now if now is not None else _utcnow
        self._id_counter = 0

        self._agents = {}            # id -> Agent
        self._agent_name_index = {}  # lower(name) -> id
        self._tasks = {}             # id -> Task
        self._messages = []          # list[Message]
        self._notifications = []     # list[Notification]
        self._history = []           # list[HistoryEntry]

        self.auto_assign_on_create = bool(auto_assign_on_create)
        self.auto_reassign = bool(auto_reassign)

    # -- internal helpers ---------------------------------------------------
    def _next_id(self):
        self._id_counter += 1
        return self._id_counter

    def _stamp(self):
        return _as_aware(self._now())

    def _get_agent_or_raise(self, agent_id):
        agent = self._agents.get(agent_id)
        if agent is None:
            raise NotFoundError("no agent with id %r" % (agent_id,))
        return agent

    def _get_task_or_raise(self, task_id):
        task = self._tasks.get(task_id)
        if task is None:
            raise NotFoundError("no task with id %r" % (task_id,))
        return task

    def _log(self, task_id, event, agent_id=None, note=None):
        entry = HistoryEntry(
            self._next_id(), task_id, event, agent_id, note, self._stamp()
        )
        self._history.append(entry)
        return entry

    def _notify(self, recipient_id, ntype, message, task_id=None):
        notif = Notification(
            self._next_id(), recipient_id, ntype, message, task_id, self._stamp()
        )
        self._notifications.append(notif)
        return notif

    def _urgency_key(self, task):
        """Sort key: most urgent first (high priority, nearest deadline)."""
        return (
            -task.priority.value,
            _epoch(task.deadline),
            _epoch(task.created_at),
            task.id,
        )

    # ----------------------------------------------------------------------
    # Agent management
    # ----------------------------------------------------------------------
    @_synchronized
    def add_agent(self, name, skills=None, capacity=1):
        """Register a new agent and return a snapshot of it."""
        clean_name = _require_text(name, "agent name")
        key = clean_name.lower()
        if key in self._agent_name_index:
            raise ValidationError("agent name already exists: %r" % (clean_name,))
        if isinstance(capacity, bool) or not isinstance(capacity, int):
            raise ValidationError("capacity must be an integer")
        if capacity < 1:
            raise ValidationError("capacity must be >= 1")
        resource_set = _normalize_resources(skills, "skills")

        agent = Agent(self._next_id(), clean_name, resource_set, capacity, self._stamp())
        self._agents[agent.id] = agent
        self._agent_name_index[key] = agent.id
        self._log(None, "agent_added", agent_id=agent.id, note="name=%s" % clean_name)
        return agent.clone()

    @_synchronized
    def get_agent(self, agent_id):
        return self._get_agent_or_raise(agent_id).clone()

    @_synchronized
    def find_agent_by_name(self, name):
        if not isinstance(name, str):
            raise ValidationError("name must be a string")
        agent_id = self._agent_name_index.get(name.strip().lower())
        if agent_id is None:
            raise NotFoundError("no agent named %r" % (name,))
        return self._agents[agent_id].clone()

    @_synchronized
    def list_agents(self, available_only=False, online_only=False):
        agents = sorted(self._agents.values(), key=lambda a: a.id)
        if online_only:
            agents = [a for a in agents if a.online]
        if available_only:
            agents = [a for a in agents if a.has_capacity]
        return [a.clone() for a in agents]

    @_synchronized
    def update_agent(self, agent_id, name=UNSET, skills=UNSET, capacity=UNSET):
        agent = self._get_agent_or_raise(agent_id)
        if name is not UNSET:
            clean_name = _require_text(name, "agent name")
            key = clean_name.lower()
            existing = self._agent_name_index.get(key)
            if existing is not None and existing != agent_id:
                raise ValidationError("agent name already exists: %r" % (clean_name,))
            del self._agent_name_index[agent.name.lower()]
            agent.name = clean_name
            self._agent_name_index[key] = agent_id
        if skills is not UNSET:
            agent.skills = _normalize_resources(skills, "skills")
        if capacity is not UNSET:
            if isinstance(capacity, bool) or not isinstance(capacity, int):
                raise ValidationError("capacity must be an integer")
            if capacity < 1:
                raise ValidationError("capacity must be >= 1")
            if capacity < agent.load:
                raise ConflictError(
                    "capacity %d below current load %d" % (capacity, agent.load)
                )
            agent.capacity = capacity
        self._log(None, "agent_updated", agent_id=agent_id)
        return agent.clone()

    @_synchronized
    def set_agent_availability(self, agent_id, available):
        """Mark an agent online/offline, adapting the schedule as needed."""
        agent = self._get_agent_or_raise(agent_id)
        available = bool(available)
        if agent.online == available:
            return agent.clone()
        agent.online = available
        if not available:
            self._log(None, "agent_offline", agent_id=agent_id)
            self._notify(agent_id, "status", "You are now offline")
            self._handle_agent_unavailable(agent)
        else:
            self._log(None, "agent_online", agent_id=agent_id)
            self._notify(agent_id, "status", "You are now online")
            if self.auto_reassign:
                self._drain_queue_to(agent)
        return agent.clone()

    @_synchronized
    def remove_agent(self, agent_id):
        """Remove an agent; its open tasks are requeued and reassigned."""
        agent = self._get_agent_or_raise(agent_id)
        self._handle_agent_unavailable(agent)
        del self._agents[agent_id]
        self._agent_name_index.pop(agent.name.lower(), None)
        self._log(None, "agent_removed", agent_id=agent_id, note="name=%s" % agent.name)
        self._notify(None, "agent_removed", "Agent %s left" % agent.name)
        return agent.clone()

    def _handle_agent_unavailable(self, agent):
        """Detach every open task from *agent* and try to reassign each one."""
        for task_id in sorted(agent.active_task_ids):
            task = self._tasks.get(task_id)
            if task is None:
                continue
            self._detach_task(task, agent, reason="agent_unavailable")
            self._notify(agent.id, "unassigned", "Task %d reassigned away" % task_id, task_id)
            if self.auto_reassign:
                self._try_auto_assign(task)
        agent.active_task_ids.clear()

    def _drain_queue_to(self, agent):
        """Give a freshly available agent as many pending tasks as it can take."""
        if not agent.has_capacity:
            return
        for task in sorted(self._pending_tasks(), key=self._urgency_key):
            if not agent.has_capacity:
                break
            if agent.can_handle(task.required_resources):
                self._do_assign(task, agent, reason="auto")

    # ----------------------------------------------------------------------
    # Task management
    # ----------------------------------------------------------------------
    @_synchronized
    def create_task(
        self,
        name,
        description="",
        priority=Priority.MEDIUM,
        required_resources=None,
        estimated_duration=None,
        deadline=None,
        auto_assign=None,
    ):
        """Define a new task and add it to the queue."""
        clean_name = _require_text(name, "task name")
        clean_desc = _optional_text(description, "description")
        prio = Priority.coerce(priority)
        resources = _normalize_resources(required_resources, "required_resources")
        duration = _validate_number(
            estimated_duration, "estimated_duration", allow_none=True, minimum=0
        )
        due = _validate_deadline(deadline)

        task = Task(
            self._next_id(),
            clean_name,
            clean_desc,
            prio,
            resources,
            duration,
            due,
            self._stamp(),
        )
        self._tasks[task.id] = task
        self._log(task.id, "task_created", note="name=%s" % clean_name)
        self._notify(None, "task_added", "New task: %s" % clean_name, task.id)

        do_auto = self.auto_assign_on_create if auto_assign is None else bool(auto_assign)
        if do_auto:
            self._try_auto_assign(task)
        return task.clone()

    @_synchronized
    def get_task(self, task_id):
        return self._get_task_or_raise(task_id).clone()

    @_synchronized
    def list_tasks(self):
        return [t.clone() for t in sorted(self._tasks.values(), key=lambda t: t.id)]

    @_synchronized
    def update_task(
        self,
        task_id,
        name=UNSET,
        description=UNSET,
        priority=UNSET,
        required_resources=UNSET,
        estimated_duration=UNSET,
        deadline=UNSET,
    ):
        """Edit a task's mutable attributes."""
        task = self._get_task_or_raise(task_id)
        if task.status.is_terminal:
            raise ConflictError("cannot edit a %s task" % task.status.value)
        if name is not UNSET:
            task.name = _require_text(name, "task name")
        if description is not UNSET:
            task.description = _optional_text(description, "description")
        if priority is not UNSET:
            task.priority = Priority.coerce(priority)
        if required_resources is not UNSET:
            task.required_resources = _normalize_resources(
                required_resources, "required_resources"
            )
        if estimated_duration is not UNSET:
            task.estimated_duration = _validate_number(
                estimated_duration, "estimated_duration", allow_none=True, minimum=0
            )
        if deadline is not UNSET:
            task.deadline = _validate_deadline(deadline)
        task.updated_at = self._stamp()
        self._log(task_id, "task_updated")
        return task.clone()

    @_synchronized
    def set_priority(self, task_id, priority):
        """Convenience wrapper that also re-sorts the queue by urgency."""
        return self.update_task(task_id, priority=priority)

    @_synchronized
    def set_deadline(self, task_id, deadline):
        return self.update_task(task_id, deadline=deadline)

    @_synchronized
    def cancel_task(self, task_id, reason=None):
        """Cancel a task, freeing its agent."""
        task = self._get_task_or_raise(task_id)
        if task.status.is_terminal:
            raise ConflictError("task already %s" % task.status.value)
        note = _optional_text(reason, "reason") if reason is not None else None
        agent = self._release_agent(task)
        task.status = TaskStatus.CANCELLED
        task.completed_at = self._stamp()
        task.updated_at = task.completed_at
        if agent is not None:
            agent.cancelled_tasks += 1
        if note:
            task.feedback.append(
                {"agent_id": None, "note": note, "timestamp": _iso(self._stamp())}
            )
        self._log(task_id, "task_cancelled", note=note)
        if task.assigned_agent_id:
            self._notify(task.assigned_agent_id, "cancelled", "Task %d cancelled" % task_id, task_id)
        return task.clone()

    @_synchronized
    def delete_task(self, task_id):
        """Permanently remove a task (history entries are retained)."""
        task = self._get_task_or_raise(task_id)
        self._release_agent(task)
        del self._tasks[task_id]
        self._log(task_id, "task_deleted")
        return True

    def _pending_tasks(self):
        return [t for t in self._tasks.values() if t.status == TaskStatus.PENDING]

    # ----------------------------------------------------------------------
    # Assignment / reassignment
    # ----------------------------------------------------------------------
    def _select_agent(self, task):
        """Pick the best available agent for *task* (or ``None``)."""
        candidates = [
            a
            for a in self._agents.values()
            if a.has_capacity and a.can_handle(task.required_resources)
        ]
        if not candidates:
            return None
        candidates.sort(
            key=lambda a: (a.load, -a.completed_tasks, a.id)
        )
        return candidates[0]

    def _do_assign(self, task, agent, reason="manual"):
        """Attach *task* to *agent* (low level, assumes capacity checked)."""
        previous_id = task.assigned_agent_id
        if previous_id is not None and previous_id != agent.id:
            previous = self._agents.get(previous_id)
            if previous is not None:
                previous.active_task_ids.discard(task.id)
                self._notify(previous_id, "unassigned", "Task %d reassigned" % task.id, task.id)
        agent.active_task_ids.add(task.id)
        agent.assignments_count += 1
        task.assigned_agent_id = agent.id
        if not task.assigned_history or task.assigned_history[-1] != agent.id:
            task.assigned_history.append(agent.id)
        if task.status in (TaskStatus.PENDING, TaskStatus.BLOCKED):
            task.status = TaskStatus.ASSIGNED
        task.updated_at = self._stamp()
        event = "task_reassigned" if previous_id and previous_id != agent.id else "task_assigned"
        self._log(task.id, event, agent_id=agent.id, note="reason=%s" % reason)
        self._notify(agent.id, "assigned", "Assigned task %d: %s" % (task.id, task.name), task.id)
        return task

    def _detach_task(self, task, agent, reason="unassigned"):
        agent.active_task_ids.discard(task.id)
        task.assigned_agent_id = None
        if task.status in (TaskStatus.ASSIGNED, TaskStatus.IN_PROGRESS, TaskStatus.BLOCKED):
            task.status = TaskStatus.PENDING
        task.updated_at = self._stamp()
        self._log(task.id, "task_requeued", agent_id=agent.id, note="reason=%s" % reason)

    def _release_agent(self, task):
        """Remove a task from whatever agent owns it; return that agent."""
        if task.assigned_agent_id is None:
            return None
        agent = self._agents.get(task.assigned_agent_id)
        if agent is not None:
            agent.active_task_ids.discard(task.id)
        return agent

    def _try_auto_assign(self, task):
        agent = self._select_agent(task)
        if agent is None:
            return None
        return self._do_assign(task, agent, reason="auto")

    @_synchronized
    def assign_task(self, task_id, agent_id, force=False):
        """Manually assign *task_id* to *agent_id*."""
        task = self._get_task_or_raise(task_id)
        agent = self._get_agent_or_raise(agent_id)
        if task.status.is_terminal:
            raise ConflictError("cannot assign a %s task" % task.status.value)
        if not force:
            if not agent.online:
                raise ConflictError("agent %d is offline" % agent_id)
            if task.assigned_agent_id != agent_id and not agent.has_capacity:
                raise ConflictError("agent %d is at capacity" % agent_id)
            if not agent.can_handle(task.required_resources):
                missing = sorted(task.required_resources - agent.skills)
                raise ConflictError(
                    "agent %d lacks resources: %s" % (agent_id, ", ".join(missing))
                )
        self._do_assign(task, agent, reason="manual")
        return task.clone()

    @_synchronized
    def reassign_task(self, task_id, new_agent_id, force=False):
        """Move a task to a different agent."""
        return self.assign_task(task_id, new_agent_id, force=force)

    @_synchronized
    def unassign_task(self, task_id):
        """Return a task to the pending queue."""
        task = self._get_task_or_raise(task_id)
        if task.assigned_agent_id is None:
            raise ConflictError("task %d is not assigned" % task_id)
        if task.status.is_terminal:
            raise ConflictError("task already %s" % task.status.value)
        agent = self._agents.get(task.assigned_agent_id)
        if agent is not None:
            self._detach_task(task, agent, reason="manual_unassign")
            self._notify(agent.id, "unassigned", "Task %d unassigned" % task_id, task_id)
        else:
            task.assigned_agent_id = None
            task.status = TaskStatus.PENDING
        return task.clone()

    @_synchronized
    def auto_assign(self, task_id):
        """Try to assign one pending task to the best available agent."""
        task = self._get_task_or_raise(task_id)
        if task.status.is_terminal:
            raise ConflictError("cannot assign a %s task" % task.status.value)
        if task.assigned_agent_id is not None:
            raise ConflictError("task %d already assigned" % task_id)
        agent = self._try_auto_assign(task)
        return None if agent is None else task.clone()

    @_synchronized
    def schedule(self):
        """Assign as many pending tasks as possible, most urgent first.

        Returns a list of ``(task_id, agent_id)`` pairs describing the
        assignments that were made.
        """
        assignments = []
        for task in sorted(self._pending_tasks(), key=self._urgency_key):
            agent = self._select_agent(task)
            if agent is not None:
                self._do_assign(task, agent, reason="auto")
                assignments.append((task.id, agent.id))
        return assignments

    @_synchronized
    def rebalance(self):
        """Adapt to urgency: preempt not-yet-started low-priority work so that
        higher-priority pending tasks can run.

        Only tasks in the ``ASSIGNED`` state (work has not begun) are eligible
        for preemption, which keeps the operation safe and non-destructive.
        Returns the list of assignments made for previously pending tasks.
        """
        made = self.schedule()
        pending = sorted(self._pending_tasks(), key=self._urgency_key)
        for task in pending:
            if task.assigned_agent_id is not None:
                continue
            victim = self._find_preemptible(task)
            if victim is None:
                continue
            victim_task, holder = victim
            self._detach_task(victim_task, holder, reason="preempted")
            self._notify(
                holder.id, "preempted",
                "Task %d preempted for higher priority task %d" % (victim_task.id, task.id),
                victim_task.id,
            )
            self._do_assign(task, holder, reason="rebalance")
            made.append((task.id, holder.id))
        return made

    def _find_preemptible(self, task):
        """Find a lower-priority, not-yet-started task whose agent could take *task*."""
        best = None
        for other in self._tasks.values():
            if other.status != TaskStatus.ASSIGNED:
                continue
            if other.priority.value >= task.priority.value:
                continue
            holder = self._agents.get(other.assigned_agent_id)
            if holder is None or not holder.online:
                continue
            if not holder.can_handle(task.required_resources):
                continue
            key = (other.priority.value, _epoch(other.deadline), other.id)
            if best is None or key < best[0]:
                best = (key, other, holder)
        if best is None:
            return None
        return best[1], best[2]

    # ----------------------------------------------------------------------
    # Execution / progress feedback
    # ----------------------------------------------------------------------
    @_synchronized
    def start_task(self, task_id, agent_id=None):
        """Mark an assigned task as in-progress."""
        task = self._get_task_or_raise(task_id)
        if task.assigned_agent_id is None:
            raise ConflictError("task %d is not assigned" % task_id)
        if agent_id is not None and agent_id != task.assigned_agent_id:
            raise ConflictError("task %d is not assigned to agent %r" % (task_id, agent_id))
        if task.status == TaskStatus.IN_PROGRESS:
            return task.clone()
        if task.status.is_terminal:
            raise ConflictError("task already %s" % task.status.value)
        task.status = TaskStatus.IN_PROGRESS
        if task.started_at is None:
            task.started_at = self._stamp()
        task.updated_at = self._stamp()
        self._log(task_id, "task_started", agent_id=task.assigned_agent_id)
        return task.clone()

    @_synchronized
    def update_progress(self, task_id, percent, note=None, agent_id=None):
        """Record progress (0..100) on a task, auto-starting it if needed."""
        task = self._get_task_or_raise(task_id)
        value = _validate_number(percent, "percent", allow_none=False, minimum=0)
        if value > 100:
            raise ValidationError("percent must be <= 100")
        if task.status.is_terminal:
            raise ConflictError("cannot update a %s task" % task.status.value)
        if task.assigned_agent_id is None:
            raise ConflictError("task %d is not assigned" % task_id)
        if agent_id is not None and agent_id != task.assigned_agent_id:
            raise ConflictError("task %d is not assigned to agent %r" % (task_id, agent_id))
        if task.status == TaskStatus.ASSIGNED:
            task.status = TaskStatus.IN_PROGRESS
            if task.started_at is None:
                task.started_at = self._stamp()
            self._log(task_id, "task_started", agent_id=task.assigned_agent_id)
        elif task.status == TaskStatus.BLOCKED:
            task.status = TaskStatus.IN_PROGRESS
        task.progress = value
        task.updated_at = self._stamp()
        clean_note = _optional_text(note, "note") if note is not None else None
        if clean_note:
            task.feedback.append(
                {
                    "agent_id": task.assigned_agent_id,
                    "note": clean_note,
                    "timestamp": _iso(task.updated_at),
                }
            )
        self._log(
            task_id, "progress_updated", agent_id=task.assigned_agent_id,
            note="%.1f%%" % value,
        )
        return task.clone()

    @_synchronized
    def update_status(self, task_id, status, note=None):
        """Generic status transition with consistent timestamp handling."""
        task = self._get_task_or_raise(task_id)
        new_status = TaskStatus.coerce(status)
        if new_status == TaskStatus.COMPLETED:
            return self.complete_task(task_id, feedback=note)
        if new_status == TaskStatus.CANCELLED:
            return self.cancel_task(task_id, reason=note)
        if task.status.is_terminal:
            raise ConflictError("task already %s" % task.status.value)
        if new_status in (TaskStatus.ASSIGNED, TaskStatus.IN_PROGRESS, TaskStatus.BLOCKED):
            if task.assigned_agent_id is None and new_status != TaskStatus.PENDING:
                raise ConflictError("task %d must be assigned first" % task_id)
        if new_status == TaskStatus.IN_PROGRESS and task.started_at is None:
            task.started_at = self._stamp()
        if new_status == TaskStatus.PENDING and task.assigned_agent_id is not None:
            agent = self._agents.get(task.assigned_agent_id)
            if agent is not None:
                self._detach_task(task, agent, reason="status_pending")
            else:
                task.assigned_agent_id = None
        task.status = new_status
        task.updated_at = self._stamp()
        clean_note = _optional_text(note, "note") if note is not None else None
        self._log(task_id, "status_%s" % new_status.value, agent_id=task.assigned_agent_id, note=clean_note)
        return task.clone()

    @_synchronized
    def report_issue(self, task_id, description, agent_id=None, block=False):
        """Attach an issue to a task; optionally mark it blocked."""
        task = self._get_task_or_raise(task_id)
        text = _require_text(description, "description")
        if agent_id is not None:
            agent = self._get_agent_or_raise(agent_id)
            agent.issues_reported += 1
        issue = {
            "agent_id": agent_id,
            "description": text,
            "timestamp": _iso(self._stamp()),
        }
        task.issues.append(issue)
        if block and not task.status.is_terminal:
            task.status = TaskStatus.BLOCKED
        task.updated_at = self._stamp()
        self._log(task_id, "issue_reported", agent_id=agent_id, note=text)
        self._notify(None, "issue", "Issue on task %d: %s" % (task_id, text), task_id)
        return task.clone()

    @_synchronized
    def complete_task(self, task_id, feedback=None, agent_id=None):
        """Mark a task complete; frees the agent and pulls the next task."""
        task = self._get_task_or_raise(task_id)
        if task.status.is_terminal:
            raise ConflictError("task already %s" % task.status.value)
        if task.assigned_agent_id is None:
            raise ConflictError("task %d is not assigned" % task_id)
        if agent_id is not None and agent_id != task.assigned_agent_id:
            raise ConflictError("task %d is not assigned to agent %r" % (task_id, agent_id))
        agent = self._agents.get(task.assigned_agent_id)
        now = self._stamp()
        if task.started_at is None:
            task.started_at = now
        task.status = TaskStatus.COMPLETED
        task.completed_at = now
        task.progress = 100.0
        task.updated_at = now
        clean_note = _optional_text(feedback, "feedback") if feedback is not None else None
        if clean_note:
            task.feedback.append(
                {"agent_id": task.assigned_agent_id, "note": clean_note, "timestamp": _iso(now)}
            )
        duration = task.duration_seconds() or 0.0
        if agent is not None:
            agent.active_task_ids.discard(task.id)
            agent.completed_tasks += 1
            agent.total_completion_seconds += duration
        self._log(
            task_id, "task_completed", agent_id=task.assigned_agent_id,
            note=clean_note or ("%.1fs" % duration),
        )
        if task.assigned_agent_id is not None:
            self._notify(task.assigned_agent_id, "completed", "Task %d completed" % task_id, task_id)
        # Adapt: pull the next pending task for the now-freed agent.
        if self.auto_reassign and agent is not None and agent.has_capacity:
            self._drain_queue_to(agent)
        return task.clone()

    # -- progress queries ---------------------------------------------------
    @_synchronized
    def time_to_completion(self, task_id):
        """Estimated seconds remaining (``None`` if it cannot be estimated)."""
        task = self._get_task_or_raise(task_id)
        return self._time_to_completion(task)

    def _time_to_completion(self, task):
        if task.status == TaskStatus.COMPLETED:
            return 0.0
        if task.status == TaskStatus.CANCELLED:
            return None
        remaining_fraction = max(0.0, 1.0 - task.progress / 100.0)
        if task.estimated_duration is not None:
            return task.estimated_duration * remaining_fraction
        # Derive from observed throughput if the task is underway.
        if task.started_at is not None and task.progress > 0:
            elapsed = (self._stamp() - task.started_at).total_seconds()
            if elapsed > 0:
                rate = task.progress / elapsed  # percent per second
                if rate > 0:
                    return (100.0 - task.progress) / rate
        return None

    @_synchronized
    def estimated_completion_time(self, task_id):
        """Projected wall-clock completion :class:`datetime` (or ``None``)."""
        task = self._get_task_or_raise(task_id)
        eta = self._time_to_completion(task)
        if eta is None:
            return None
        if task.status == TaskStatus.COMPLETED:
            return task.completed_at
        return self._stamp() + timedelta(seconds=eta)

    @_synchronized
    def get_progress(self, task_id):
        """Return a rich real-time feedback snapshot for a task."""
        task = self._get_task_or_raise(task_id)
        eta = self._time_to_completion(task)
        eta_dt = None
        if eta is not None and task.status != TaskStatus.COMPLETED:
            eta_dt = self._stamp() + timedelta(seconds=eta)
        elif task.status == TaskStatus.COMPLETED:
            eta_dt = task.completed_at
        return {
            "task_id": task.id,
            "name": task.name,
            "status": task.status.value,
            "progress": task.progress,
            "assigned_agent_id": task.assigned_agent_id,
            "eta_seconds": eta,
            "estimated_completion": _iso(eta_dt),
            "is_overdue": task.is_overdue(self._stamp()),
            "open_issues": len(task.issues),
            "issues": [dict(i) for i in task.issues],
        }

    # ----------------------------------------------------------------------
    # Communication: chat & notifications
    # ----------------------------------------------------------------------
    @_synchronized
    def post_message(self, sender_id, content, task_id=None, recipient_id=None):
        """Post a chat message (recipient ``None`` == broadcast)."""
        sender = self._get_agent_or_raise(sender_id)
        text = _require_text(content, "content")
        if recipient_id is not None:
            self._get_agent_or_raise(recipient_id)
        if task_id is not None:
            self._get_task_or_raise(task_id)
        message = Message(
            self._next_id(), sender.id, recipient_id, task_id, text, self._stamp()
        )
        self._messages.append(message)
        if recipient_id is not None:
            self._notify(recipient_id, "message", "Message from agent %d" % sender_id, task_id)
        else:
            self._notify(None, "message", "Broadcast from agent %d" % sender_id, task_id)
        return message.clone()

    @_synchronized
    def broadcast(self, sender_id, content, task_id=None):
        """Shorthand for a message visible to every agent."""
        return self.post_message(sender_id, content, task_id=task_id, recipient_id=None)

    @_synchronized
    def get_messages(self, agent_id=None, task_id=None, since=None):
        """Read the chat feed, optionally filtered.

        When *agent_id* is given, broadcasts plus messages sent by or to that
        agent are returned.
        """
        if agent_id is not None:
            self._get_agent_or_raise(agent_id)
        if task_id is not None:
            self._get_task_or_raise(task_id)
        since_dt = _as_aware(since) if isinstance(since, datetime) else None
        out = []
        for msg in self._messages:
            if task_id is not None and msg.task_id != task_id:
                continue
            if agent_id is not None and not (
                msg.is_broadcast or msg.sender_id == agent_id or msg.recipient_id == agent_id
            ):
                continue
            if since_dt is not None and msg.timestamp <= since_dt:
                continue
            out.append(msg.clone())
        return out

    @_synchronized
    def get_notifications(self, agent_id=None, unread_only=False, mark_read=False):
        """Read notifications for an agent (broadcasts included)."""
        if agent_id is not None:
            self._get_agent_or_raise(agent_id)
        out = []
        for notif in self._notifications:
            if agent_id is not None and not (
                notif.recipient_id is None or notif.recipient_id == agent_id
            ):
                continue
            if unread_only and notif.read:
                continue
            out.append(notif)
        result = [n.clone() for n in out]
        if mark_read:
            for notif in out:
                notif.read = True
        return result

    @_synchronized
    def mark_notifications_read(self, agent_id=None):
        count = 0
        for notif in self._notifications:
            if agent_id is not None and not (
                notif.recipient_id is None or notif.recipient_id == agent_id
            ):
                continue
            if not notif.read:
                notif.read = True
                count += 1
        return count

    # ----------------------------------------------------------------------
    # Views: filter / sort / search / queue
    # ----------------------------------------------------------------------
    @_synchronized
    def filter_tasks(
        self,
        status=None,
        priority=None,
        agent_id=None,
        resource=None,
        unassigned=None,
        overdue=None,
    ):
        """Return task snapshots matching every supplied criterion."""
        status_f = TaskStatus.coerce(status) if status is not None else None
        priority_f = Priority.coerce(priority) if priority is not None else None
        resource_f = resource.strip().lower() if isinstance(resource, str) else None
        now = self._stamp()
        out = []
        for task in self._tasks.values():
            if status_f is not None and task.status != status_f:
                continue
            if priority_f is not None and task.priority != priority_f:
                continue
            if agent_id is not None and task.assigned_agent_id != agent_id:
                continue
            if unassigned is True and task.assigned_agent_id is not None:
                continue
            if unassigned is False and task.assigned_agent_id is None:
                continue
            if resource_f is not None and resource_f not in task.required_resources:
                continue
            if overdue is True and not task.is_overdue(now):
                continue
            if overdue is False and task.is_overdue(now):
                continue
            out.append(task.clone())
        out.sort(key=lambda t: t.id)
        return out

    @_synchronized
    def search_tasks(self, query):
        """Case-insensitive substring search over name and description."""
        if not isinstance(query, str):
            raise ValidationError("query must be a string")
        needle = query.strip().lower()
        out = []
        for task in self._tasks.values():
            if not needle or needle in task.name.lower() or needle in task.description.lower():
                out.append(task.clone())
        out.sort(key=lambda t: t.id)
        return out

    @_synchronized
    def sort_tasks(self, by="priority", reverse=False, tasks=None):
        """Return tasks sorted by a named key."""
        source = list(self._tasks.values()) if tasks is None else list(tasks)
        keyers = {
            "priority": lambda t: self._urgency_key(t),
            "created": lambda t: (_epoch(t.created_at), t.id),
            "deadline": lambda t: (_epoch(t.deadline), t.id),
            "name": lambda t: (t.name.lower(), t.id),
            "status": lambda t: (t.status.value, t.id),
            "progress": lambda t: (t.progress, t.id),
            "id": lambda t: t.id,
        }
        if by not in keyers:
            raise ValidationError("unknown sort key: %r" % (by,))
        source.sort(key=keyers[by], reverse=reverse)
        return [t.clone() if isinstance(t, Task) else t for t in source]

    @_synchronized
    def get_queue(self):
        """Pending tasks ordered most-urgent-first."""
        return [
            t.clone()
            for t in sorted(self._pending_tasks(), key=self._urgency_key)
        ]

    # ----------------------------------------------------------------------
    # Performance monitoring & dashboards
    # ----------------------------------------------------------------------
    @_synchronized
    def agent_performance(self, agent_id):
        agent = self._get_agent_or_raise(agent_id)
        return self._agent_performance(agent)

    def _agent_performance(self, agent):
        return {
            "agent_id": agent.id,
            "name": agent.name,
            "status": agent.status.value,
            "online": agent.online,
            "capacity": agent.capacity,
            "current_load": agent.load,
            "active_task_ids": sorted(agent.active_task_ids),
            "completed_tasks": agent.completed_tasks,
            "cancelled_tasks": agent.cancelled_tasks,
            "assignments_count": agent.assignments_count,
            "issues_reported": agent.issues_reported,
            "average_completion_seconds": agent.average_completion_seconds,
            "skills": sorted(agent.skills),
        }

    @_synchronized
    def performance_report(self):
        return [
            self._agent_performance(a)
            for a in sorted(self._agents.values(), key=lambda a: a.id)
        ]

    @_synchronized
    def dashboard(self):
        """Aggregate metrics describing the whole system right now."""
        now = self._stamp()
        status_counts = {s.value: 0 for s in TaskStatus}
        priority_counts = {p.name: 0 for p in Priority}
        overdue = 0
        for task in self._tasks.values():
            status_counts[task.status.value] += 1
            priority_counts[task.priority.name] += 1
            if task.is_overdue(now):
                overdue += 1
        agent_status = {s.value: 0 for s in AgentStatus}
        for agent in self._agents.values():
            agent_status[agent.status.value] += 1
        return {
            "total_agents": len(self._agents),
            "agents_by_status": agent_status,
            "total_tasks": len(self._tasks),
            "tasks_by_status": status_counts,
            "tasks_by_priority": priority_counts,
            "pending_tasks": status_counts[TaskStatus.PENDING.value],
            "overdue_tasks": overdue,
            "messages": len(self._messages),
            "history_entries": len(self._history),
            "generated_at": _iso(now),
        }

    @_synchronized
    def format_dashboard(self):
        """A human-readable multi-line dashboard string."""
        data = self.dashboard()
        lines = []
        lines.append("=" * 48)
        lines.append("MultiAgentTaskScheduler Dashboard")
        lines.append("=" * 48)
        lines.append("Agents: %d total" % data["total_agents"])
        for status, count in data["agents_by_status"].items():
            lines.append("  - %-9s : %d" % (status, count))
        lines.append("Tasks: %d total (%d pending, %d overdue)" % (
            data["total_tasks"], data["pending_tasks"], data["overdue_tasks"],
        ))
        lines.append("  By status:")
        for status, count in data["tasks_by_status"].items():
            if count:
                lines.append("    - %-12s : %d" % (status, count))
        lines.append("  By priority:")
        for prio, count in data["tasks_by_priority"].items():
            if count:
                lines.append("    - %-8s : %d" % (prio, count))
        lines.append("Messages logged : %d" % data["messages"])
        lines.append("History entries : %d" % data["history_entries"])
        lines.append("=" * 48)
        return "\n".join(lines)

    # ----------------------------------------------------------------------
    # History log
    # ----------------------------------------------------------------------
    @_synchronized
    def get_history(self, task_id=None, agent_id=None):
        """Chronological audit log, optionally filtered."""
        if task_id is not None:
            self._get_task_or_raise(task_id)
        out = []
        for entry in self._history:
            if task_id is not None and entry.task_id != task_id:
                continue
            if agent_id is not None and entry.agent_id != agent_id:
                continue
            out.append(entry.clone())
        return out

    @_synchronized
    def task_report(self, task_id):
        """A complete record of a task suitable for the history log."""
        task = self._get_task_or_raise(task_id)
        agent_names = {}
        for aid in task.assigned_history:
            agent = self._agents.get(aid)
            agent_names[aid] = agent.name if agent is not None else None
        return {
            "task_id": task.id,
            "name": task.name,
            "description": task.description,
            "priority": task.priority.name,
            "status": task.status.value,
            "required_resources": sorted(task.required_resources),
            "assigned_agent_id": task.assigned_agent_id,
            "assigned_history": list(task.assigned_history),
            "assigned_agent_names": agent_names,
            "progress": task.progress,
            "start_time": _iso(task.started_at),
            "end_time": _iso(task.completed_at),
            "duration_seconds": task.duration_seconds(),
            "created_at": _iso(task.created_at),
            "deadline": _iso(task.deadline),
            "issues": [dict(i) for i in task.issues],
            "feedback": [dict(f) for f in task.feedback],
            "events": [e.to_dict() for e in self._history if e.task_id == task.id],
        }

    @_synchronized
    def export_history_csv(self):
        """Serialise the full history log as a CSV string."""
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        writer.writerow(["id", "timestamp", "task_id", "event", "agent_id", "note"])
        for entry in self._history:
            writer.writerow([
                entry.id,
                _iso(entry.timestamp),
                "" if entry.task_id is None else entry.task_id,
                entry.event,
                "" if entry.agent_id is None else entry.agent_id,
                "" if entry.note is None else entry.note,
            ])
        return buffer.getvalue()

    @_synchronized
    def export_tasks_csv(self):
        """Serialise every task as a CSV string."""
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        writer.writerow([
            "id", "name", "priority", "status", "assigned_agent_id",
            "progress", "created_at", "started_at", "completed_at", "deadline",
        ])
        for task in sorted(self._tasks.values(), key=lambda t: t.id):
            writer.writerow([
                task.id,
                task.name,
                task.priority.name,
                task.status.value,
                "" if task.assigned_agent_id is None else task.assigned_agent_id,
                task.progress,
                _iso(task.created_at),
                _iso(task.started_at),
                _iso(task.completed_at),
                _iso(task.deadline),
            ])
        return buffer.getvalue()

    # ----------------------------------------------------------------------
    # Misc
    # ----------------------------------------------------------------------
    @property
    def lock(self):
        """The shared re-entrant lock guarding this scheduler."""
        return self._lock

    def __repr__(self):  # pragma: no cover - debugging aid
        return "MultiAgentTaskScheduler(agents=%d, tasks=%d)" % (
            len(self._agents),
            len(self._tasks),
        )


