# Smoke test / demonstration
# ---------------------------------------------------------------------------
def _demo():
    """Exercise the main flows; used by ``python solution.py``."""
    scheduler = MultiAgentTaskScheduler()

    alice = scheduler.add_agent("Alice", skills=["python", "ml"], capacity=2)
    bob = scheduler.add_agent("Bob", skills=["python", "frontend"], capacity=1)

    t1 = scheduler.create_task(
        "Train model", description="Train the ranking model",
        priority="high", required_resources=["python", "ml"],
        estimated_duration=120,
    )
    t2 = scheduler.create_task(
        "Build UI", priority=Priority.MEDIUM, required_resources=["frontend"],
        estimated_duration=60,
    )
    t3 = scheduler.create_task("Write docs", priority="low")

    made = scheduler.schedule()
    assert made, "expected at least one automatic assignment"

    scheduler.start_task(t1.id, agent_id=alice.id)
    scheduler.update_progress(t1.id, 50, note="halfway", agent_id=alice.id)
    eta = scheduler.time_to_completion(t1.id)
    assert eta == 60.0, eta  # 120s estimate, 50% done

    scheduler.post_message(alice.id, "How is the UI going?", recipient_id=bob.id)
    scheduler.broadcast(alice.id, "Model training underway")
    assert len(scheduler.get_messages(agent_id=bob.id)) >= 1

    scheduler.report_issue(t2.id, "Design assets missing", agent_id=bob.id)
    scheduler.complete_task(t1.id, feedback="model trained", agent_id=alice.id)

    # Bob becomes unavailable: his task is requeued and (here) reassigned to none
    scheduler.set_agent_availability(bob.id, False)
    queued = scheduler.get_queue()
    assert any(t.id == t2.id for t in queued), "task should be back in the queue"

    report = scheduler.task_report(t1.id)
    assert report["status"] == "completed"
    assert report["start_time"] and report["end_time"]

    print(scheduler.format_dashboard())
    print("\nHistory entries:", len(scheduler.get_history()))
    print("Performance:")
    for row in scheduler.performance_report():
        print("  ", row["name"], "completed", row["completed_tasks"])
    print("\nSmoke test passed.")


if __name__ == "__main__":
    _demo()
